export type ShapeType = "rectangle" | "ellipse" | "line" | "text";

/**
 * All coordinates in canvas pixels, origin top-left.
 * Bounding-box model: (x,y) is top-left corner.
 * Line: (x,y) is start point, (x+width, y+height) is end point.
 */
export interface Shape {
  id: string;            // UUIDv4
  type: ShapeType;
  x: number;
  y: number;
  width: number;
  height: number;
  fill: string;          // "#rrggbb" or "" for none
  stroke: string;        // "#rrggbb"
  strokeWidth: number;   // >= 1
  text?: string;         // required when type === "text"
  fontSize?: number;     // required when type === "text", default 16
}

/** Properties that can be changed via update. */
export type ShapeProps = Omit<Shape, "id" | "type">;

// ├втАЭтВм├втАЭтВм Operations ├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм

export type Operation =
  | { kind: "add"; shape: Shape }
  | { kind: "update"; shapeId: string; props: Partial<ShapeProps> }
  | { kind: "delete"; shapeId: string };

// ├втАЭтВм├втАЭтВм Undo / Redo (client-side only) ├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм

/**
 * Client maintains per-user undo + redo stacks.
 * Undo: pop ├втАатАЩ send reverse as a regular op to server.
 * Redo: pop ├втАатАЩ send forward as a regular op to server.
 * Server has no undo concept ├втВмтАЭ it only sees normal operations.
 *
 * Building the entry:
 *   add    ├втАатАЩ reverse is { kind:"delete", shapeId }
 *   delete ├втАатАЩ reverse is { kind:"add", shape: <snapshot before delete> }
 *   update ├втАатАЩ reverse is { kind:"update", shapeId, props: <old values> }
 */
export interface UndoEntry {
  forward: Operation;
  reverse: Operation;
}

// ├втАЭтВм├втАЭтВм WebSocket Protocol ├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм

