export type ClientMessage =
  | { type: "op"; op: Operation }
  | { type: "cursor"; x: number; y: number };

/** Server ├втАатАЩ Client (JSON over text frames) */
export type ServerMessage =
  | { type: "init"; shapes: Shape[]; users: PresenceUser[] }
  | { type: "op"; op: Operation; userId: string }
