 206: export function hitTest(shapes: Shape[], x: number, y: number): Shape | null {
 207:   // Iterate in reverse z-order (topmost first)
 208:   for (let i = shapes.length - 1; i >= 0; i--) {
 209:     const s = shapes[i];
 210:     if (isPointInShape(s, x, y)) {
 211:       return s;
 212:     }
