 217: function isPointInShape(shape: Shape, px: number, py: number): boolean {
 218:   const margin = 4;
 219:   switch (shape.type) {
 220:     case "rectangle":
 221:     case "text":
 222:       return (
 223:         px >= shape.x - margin &&
 224:         px <= shape.x + shape.width + margin &&
 225:         py >= shape.y - margin &&
 226:         py <= shape.y + shape.height + margin
 227:       );
 228: 
 229:     case "ellipse": {
 230:       const cx = shape.x + shape.width / 2;
 231:       const cy = shape.y + shape.height / 2;
 232:       const rx = Math.abs(shape.width / 2) + margin;
 233:       const ry = Math.abs(shape.height / 2) + margin;
 234:       if (rx === 0 || ry === 0) return false;
 235:       const dx = px - cx;
 236:       const dy = py - cy;
 237:       return (dx * dx) / (rx * rx) + (dy * dy) / (ry * ry) <= 1;
 238:     }
 239: 
 240:     case "line": {
 241:       // Check distance from point to line segment
 242:       const x1 = shape.x;
 243:       const y1 = shape.y;
 244:       const x2 = shape.x + shape.width;
 245:       const y2 = shape.y + shape.height;
 246:       const dist = distToSegment(px, py, x1, y1, x2, y2);
 247:       return dist <= shape.strokeWidth / 2 + margin + 4;
 248:     }
 249: 
 250:     default:
 251:       return false;
 252:   }
 253: }
