 255: function distToSegment(
 256:   px: number,
 257:   py: number,
 258:   x1: number,
 259:   y1: number,
 260:   x2: number,
 261:   y2: number
 262: ): number {
 263:   const dx = x2 - x1;
 264:   const dy = y2 - y1;
 265:   const lenSq = dx * dx + dy * dy;
 266:   if (lenSq === 0) return Math.sqrt((px - x1) ** 2 + (py - y1) ** 2);
 267:   let t = ((px - x1) * dx + (py - y1) * dy) / lenSq;
 268:   t = Math.max(0, Math.min(1, t));
 269:   const projX = x1 + t * dx;
 270:   const projY = y1 + t * dy;
 271:   return Math.sqrt((px - projX) ** 2 + (py - projY) ** 2);
 272: }
